import { setup, assign } from 'xstate';

export const machine = setup({
  types: {
    context: {} as Record<string, unknown>,
    events: {} as   | { type: 'DONE' }
  | { type: 'ERROR' }
  | { type: 'RETRY' }
  | { type: 'SUBMIT' },
  },
}).createMachine({
  initial: 'idle',
  states: {
    error: {
      on: {
        RETRY: 'idle',
      },
    },
    idle: {
      on: {
        SUBMIT: 'loading',
      },
    },
    loading: {
      on: {
        DONE: {
          target: 'success',
          actions: assign({}),
        },
        ERROR: {
          target: 'error',
          actions: assign({}),
        },
      },
    },
    success: {},
  },
});
